import React from 'react';
import { Link } from 'react-router-dom'; // Importa Link para la navegación interna

const Footer = () => {
  return (
    <footer style={styles.footerContainer}>
      <div style={styles.footerContent}>
        {/* Sección 1: Más información - REDUCIDA */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>más información</h3>
          <ul style={styles.linkListSingle}> {/* Usamos linkListSingle para una sola columna */}
            <li><Link to="/empresas" style={styles.link}>Empresas</Link></li>
            <li><Link to="/historia" style={styles.link}>Nuestra Historia</Link></li>
            <li><a href="#" style={styles.link}>Novedades</a></li>
            <li><Link to="/contacto" style={styles.link}>Contacto</Link></li>
            {/* Eliminados: Tienda, Productos, Recompensas, Recomienda un amigo, Únete al equipo */}
          </ul>
        </div>

        {/* Sección 2: Encuéntranos / Club de Correo / Redes Sociales - COMPACTADA */}
        <div style={styles.sectionCenter}>
          <h3 style={styles.sectionTitle}>encuéntranos</h3>
          <button style={styles.storeLocatorButton}>UBICADOR DE TIENDAS</button>

          <h3 style={{ ...styles.sectionTitle, marginTop: '20px' }}>club de correo</h3> {/* Reducido marginTop */}
          <p style={styles.emailClubText}>Sé el primero en recibir ofertas y noticias.</p> {/* Texto más conciso */}
          <div style={styles.emailInputContainer}>
            <input type="email" placeholder="tu correo electrónico" style={styles.emailInput} />
            <button style={styles.emailSubmitButton}>&rarr;</button>
          </div>
          <div style={styles.socialIcons}>
            <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-facebook-f"></i></a>
            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-instagram"></i></a>
            <a href="https://tiktok.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-tiktok"></i></a>
          </div>
        </div>

        {/* Sección 3: Necesitas ayuda? - SIN CAMBIOS SIGNIFICATIVOS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>necesitas ayuda?</h3>
          <ul style={styles.linkListSingle}>
            <li><a href="#" style={styles.link}>Envíos y devoluciones</a></li>
            <li><Link to="/contacto" style={styles.link}>Contacta con nosotros</Link></li>
            <li><a href="#" style={styles.link}>Venta al por mayor</a></li>
            <li><Link to="/privacidad" style={styles.link}>Política de Privacidad</Link></li>
            <li><a href="#" style={styles.link}>Términos del servicio</a></li>
            <li><a href="#" style={styles.link}>Preguntas frecuentes</a></li>
            <li><a href="#" style={styles.link}>Mapa del sitio</a></li>
          </ul>
        </div>
      </div>

      {/* Sección de créditos "Titulizado por Alberto Navarro" */}
      <div style={styles.creditsBar}>
        <p style={styles.creditsText}>Titulizado por Alberto Navarro</p>
      </div>

      {/* Barra inferior "PAQUETE DE VARIEDADES GRATIS" - Sigue comentada */}
      {/* <div style={styles.bottomBar}>
        <span style={styles.bottomBarText}>PAQUETE DE VARIEDADES GRATIS</span>
        <button style={styles.bottomBarClose}>&times;</button>
      </div> */}
    </footer>
  );
};

const styles = {
  footerContainer: {
    backgroundImage: "url('/media/footer2.png')", // Mantener la imagen de fondo
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundRepeat: 'no-repeat',
    backgroundColor: '#F8F6F1',
    padding: '40px 20px 15px 20px', // REDUCIR PADDING: '60px 20px 20px 20px' -> '40px 20px 15px 20px'
    color: '#333',
    fontFamily: "'Poppins', sans-serif",
    borderTop: '1px solid #eee',
    boxShadow: '0 -2px 10px rgba(0,0,0,0.05)',
  },
  footerContent: {
    display: 'flex',
    justifyContent: 'space-around',
    flexWrap: 'wrap',
    maxWidth: '1000px', // REDUCIR ANCHO MÁXIMO: '1200px' -> '1000px'
    margin: '0 auto',
    gap: '30px', // REDUCIR ESPACIO ENTRE COLUMNAS: '40px' -> '30px'
    marginBottom: '20px', // REDUCIR ESPACIO: '30px' -> '20px'
  },
  section: {
    flex: '1 1 200px', // REDUCIR FLEX-BASIS: '280px' -> '200px'
    minWidth: '180px', // Ajuste mínimo
  },
  sectionCenter: {
    flex: '1 1 300px', // REDUCIR FLEX-BASIS: '350px' -> '300px'
    minWidth: '220px', // Ajuste mínimo
    textAlign: 'center',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  sectionTitle: {
    fontSize: '1.1rem', // REDUCIR TAMAÑO DE FUENTE: '1.2rem' -> '1.1rem'
    fontWeight: 'bold',
    marginBottom: '15px', // REDUCIR MARGEN: '20px' -> '15px'
    textTransform: 'uppercase',
  },
  linksColumn: {
    display: 'flex',
    justifyContent: 'space-between',
    gap: '15px', // REDUCIR ESPACIO: '20px' -> '15px'
  },
  linkList: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
  },
  linkListSingle: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
    lineHeight: '1.6', // REDUCIR LINE-HEIGHT: '1.8' -> '1.6'
  },
  link: {
    textDecoration: 'none',
    color: '#333',
    fontSize: '0.9rem', // REDUCIR TAMAÑO DE FUENTE: '0.95rem' -> '0.9rem'
    transition: 'color 0.3s ease',
    '&:hover': {
      color: '#166D3B',
    },
  },
  storeLocatorButton: {
    backgroundColor: '#333',
    color: 'white',
    border: 'none',
    padding: '10px 20px', // REDUCIR PADDING: '12px 25px' -> '10px 20px'
    borderRadius: '5px',
    cursor: 'pointer',
    fontSize: '0.85rem', // REDUCIR TAMAÑO DE FUENTE: '0.9rem' -> '0.85rem'
    fontWeight: 'bold',
    textTransform: 'uppercase',
    marginTop: '5px', // REDUCIR MARGEN: '10px' -> '5px'
    transition: 'background-color 0.3s ease',
    '&:hover': {
      backgroundColor: '#166D3B',
    },
  },
  emailClubText: {
    fontSize: '0.85rem', // REDUCIR TAMAÑO DE FUENTE: '0.9rem' -> '0.85rem'
    color: '#666',
    marginBottom: '10px', // REDUCIR MARGEN: '15px' -> '10px'
  },
  emailInputContainer: {
    display: 'flex',
